// Deterministic per-question option shuffle so the correct answer isn't always "A".
// Seeded by the question id, so the same question yields the same shuffle for
// every client (important for Online Versus where both players must agree).
function _hash(s: string): number {
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
}
function _mulberry32(seed: number) {
  let a = seed || 1;
  return () => {
    a |= 0; a = (a + 0x6D2B79F5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
for (const _key of Object.keys(QUESTIONS)) {
  for (const _q of QUESTIONS[_key]) {
    if (!_q.options || _q.options.length < 2) continue;
    const rng = _mulberry32(_hash(_q.id));
    const order = _q.options.map((_, i) => i);
    for (let i = order.length - 1; i > 0; i--) {
      const j = Math.floor(rng() * (i + 1));
      [order[i], order[j]] = [order[j], order[i]];
    }
    _q.options = order.map((i) => _q.options[i]);
    _q.answer = order.indexOf(_q.answer);
  }
}

